Here's a complete test class using modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private MockHttpMessageHandler _handler = null!;
    private DataFetcher _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _handler = new MockHttpMessageHandler();
        _sut = new DataFetcher(new HttpClient(_handler));
    }

    // Async tests: just return Task — MSTest awaits it natively
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_WhenSuccessful()
    {
        _handler.ResponseContent = "hello";
        _handler.StatusCode = HttpStatusCode.OK;

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // Timeouts: use [Timeout] attribute (milliseconds) to catch hangs
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        _handler.ResponseContent = "fast";
        _handler.StatusCode = HttpStatusCode.OK;

        var result = await _sut.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Cancellation: verify the token is respected
    [TestMethod]
    public async Task FetchAsync_ThrowsWhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => _sut.FetchAsync("https://example.com", cts.Token));
    }

    // Error status codes: verify EnsureSuccessStatusCode throws
    [TestMethod]
    public async Task FetchAsync_ThrowsOnNonSuccessStatus()
    {
        _handler.StatusCode = HttpStatusCode.InternalServerError;

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => _sut.FetchAsync("https://example.com"));
    }

    // Minimal mock handler — no external mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpStatusCode StatusCode { get; set; } = HttpStatusCode.OK;
        public string ResponseContent { get; set; } = string.Empty;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(StatusCode)
            {
                Content = new StringContent(ResponseContent)
            });
        }
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Async tests** | Return `Task`, use `async/await` — MSTest handles it natively |
| **Timeouts** | `[Timeout(ms)]` attribute fails the test if it hangs |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **Exception testing** | `Assert.ThrowsExceptionAsync<T>()` for async exception paths |
| **HttpClient mocking** | Custom `HttpMessageHandler` — avoids mocking framework dependencies |
